<template>
    <div>
      <div class="content">
        <h1>{{ $t('ldgwelcome') }}</h1>
        <p>{{ $t('ldgdescription') }}</p>
        <button @click="changeLanguage">{{ $t('changeLanguage') }}</button>

        <div class="overlay-container">
            <div class="main-box">
              <div class="sub-box" v-for="overlay in overlays" :key="overlay.id">
                <button @click="openOverlay(overlay.id)">
                  {{ overlay.id }}
                </button>

                <OverlayComponent
                  v-if="selectedOverlay"
                  :data="selectedOverlay"
                  @close="selectedOverlay = null"
                />
            </div>
          </div>
            
        </div>
      </div>
    </div>
  </template>

  <script>
  import OverlayComponent from './OverlayComponent.vue';

    export default {
    components: {
      OverlayComponent
    },
    methods: {
      changeLanguage() {
        this.$i18n.locale = this.$i18n.locale === 'en' ? 'es' : 'en';
      },
      async fetchOverlays() {
        try {
          const response = await fetch("https://67e2f7f097fc65f535384c4d.mockapi.io/Projects"); 
          this.overlays = await response.json();
        } catch (error) {
          console.error("Error during data fetching :", error)
        }
      },
      openOverlay(id) {
        console.log("open Overlay "+id);
        this.selectedOverlay = this.overlays.find(overlay => overlay.id === id);
      }
    },
    data() {
      return {
        overlays: [],
        selectedOverlay: null
      }
    },
    mounted() {
      this.fetchOverlays();
    }
  };
  </script>
  
  
